// Add validation first
if (!items || items.length === 0) {
  throw new Error('No items found');
}

// Check different possible data locations
let csvText;
if (items[0].data) {
  csvText = items[0].data;
} else if (items[0].json && items[0].json.data) {
  csvText = items[0].json.data;
} else if (items[0].json && items[0].json.body && items[0].json.body.data) {
  csvText = items[0].json.body.data;
} else {
  throw new Error('Could not find CSV data. Available keys: ' + Object.keys(items[0]).join(', '));
}

// Split CSV into lines
const lines = csvText.trim().split('\r\n');
// Extract headers
const headers = lines[0].split(',').map(h => h.trim());
// Identify columns
const nameCol = headers.find(h => /name/i.test(h));
const phoneCol = headers.find(h => /phone/i.test(h));

// CSV parser (handles quotes)
function parseCSVRow(line) {
  const row = [];
  let current = '';
  let inQuotes = false;
  for (const char of line) {
    if (char === '"') inQuotes = !inQuotes;
    else if (char === ',' && !inQuotes) {
      row.push(current);
      current = '';
    } else current += char;
  }
  row.push(current);
  return row.map(v => v.replace(/^"|"$/g, '').trim());
}

// Get agent_id from Webhook
const agentId = $('Webhook').item.json.body.agent_id;

// Build output
const output = [];
for (let i = 1; i < lines.length; i++) {
  const line = lines[i].trim();
  // Skip empty lines
  if (!line || line === ',') continue;

  const values = parseCSVRow(line);
  const row = {};
  headers.forEach((h, idx) => row[h] = values[idx] || '');

  const name = row[nameCol] || '';
  let number = row[phoneCol] || '';

  // Skip rows with empty name AND number
  if (!name && !number) continue;

  if (number && !number.startsWith('+')) number = '+' + number.replace(/^\+/, '');

  output.push({ 
    json: { 
      name, 
      number,
      agent_id: agentId
    } 
  });
}

return output;

// Check if this is a single item or multiple items
