// Process ALL items
const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;

  // The ISO string format: "2026-01-22T13:36:45.563-08:00"
  // We need to extract the hour from THIS timezone, not convert it

  // Extract the time portion and timezone offset
  const isoString = data.currentDate;

  // Parse the ISO date
  const date = new Date(isoString);

  // Get the timezone offset from the ISO string
  const match = isoString.match(/T(\d{2}):(\d{2}):(\d{2})/);
  const currentHour = match ? parseInt(match[1], 10) : date.getHours();
  const currentMinute = match ? parseInt(match[2], 10) : date.getMinutes();

  // Check if time is between 8 PM (20:00) and 8 AM (08:00)
  // Night hours: 20:00-23:59 OR 00:00-07:59
  const isNightTime = currentHour >= 20 || currentHour < 8;

  output.push({
    json: {
      ...data, // Keep all previous data (phone_number, country, timezone, etc.)
      is_night_time: isNightTime,
      can_make_call: !isNightTime,
      current_hour_24: currentHour,
      current_time: `${String(currentHour).padStart(2,'0')}:${String(currentMinute).padStart(2,'0')}`,
      timezone_used: data.currentDate,
      message: isNightTime 
        ? "Night time (8 PM - 8 AM): Do not call" 
        : "Day time (8 AM - 8 PM): Safe to call"
    }
  });
}

return output;

// Add validation first
if (!items || items.length === 0) {
  throw new Error('No items found');
}

// Check different possible data locations
let csvText;
if (items[0].data) {
  csvText = items[0].data;
} else if (items[0].json && items[0].json.data) {
  csvText = items[0].json.data;
} else if (items[0].json && items[0].json.body && items[0].json.body.data) {
  csvText = items[0].json.body.data;
} else {
  throw new Error('Could not find CSV data. Available keys: ' + Object.keys(items[0]).join(', '));
}

// Split CSV into lines
const lines = csvText.trim().split('\r\n');
// Extract headers
const headers = lines[0].split(',').map(h => h.trim());
// Identify columns
const nameCol = headers.find(h => /name/i.test(h));
const phoneCol = headers.find(h => /phone/i.test(h));

// CSV parser (handles quotes)
function parseCSVRow(line) {
  const row = [];
  let current = '';
  let inQuotes = false;
  for (const char of line) {
    if (char === '"') inQuotes = !inQuotes;
    else if (char === ',' && !inQuotes) {
      row.push(current);
      current = '';
    } else current += char;
  }
  row.push(current);
  return row.map(v => v.replace(/^"|"$/g, '').trim());
}

// Get agent_id from Webhook
const agentId = $('Webhook').item.json.body.agent_id;

// Build output
const output = [];
for (let i = 1; i < lines.length; i++) {
  const line = lines[i].trim();
  // Skip empty lines
  if (!line || line === ',') continue;

  const values = parseCSVRow(line);
  const row = {};
  headers.forEach((h, idx) => row[h] = values[idx] || '');

  const name = row[nameCol] || '';
  let number = row[phoneCol] || '';

  // Skip rows with empty name AND number
  if (!name && !number) continue;

  if (number && !number.startsWith('+')) number = '+' + number.replace(/^\+/, '');

  output.push({ 
    json: { 
      name, 
      number,
      agent_id: agentId
    } 
  });
}

return output;

// Check if this is a single item or multiple items
const items = $input.all();
const output = [];

for (const item of items) {
  const body = item.json.body || item.json;

  // Handle both single call (to_number) and batch call (number/phone_number)
  const phoneNumber = body.to_number || body.number || body.phone_number;

  if (!phoneNumber) {
    output.push({ json: { error: true, message: "No phone number provided" } });
    continue;
  }

