const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;

  // The ISO string format: "2026-01-22T13:36:45.563-08:00"
  // We need to extract the hour from THIS timezone, not convert it

  // Extract the time portion and timezone offset
  const isoString = data.currentDate;

  // Parse the ISO date
  const date = new Date(isoString);

  // Get the timezone offset from the ISO string
  const match = isoString.match(/T(\d{2}):(\d{2}):(\d{2})/);
  const currentHour = match ? parseInt(match[1], 10) : date.getHours();
  const currentMinute = match ? parseInt(match[2], 10) : date.getMinutes();

  // Check if time is between 8 PM (20:00) and 8 AM (08:00)
  // Night hours: 20:00-23:59 OR 00:00-07:59
  const isNightTime = currentHour >= 20 || currentHour < 8;

  output.push({
    json: {
      ...data, // Keep all previous data (phone_number, country, timezone, etc.)
      is_night_time: isNightTime,
      can_make_call: !isNightTime,
      current_hour_24: currentHour,
      current_time: `${String(currentHour).padStart(2,'0')}:${String(currentMinute).padStart(2,'0')}`,
      timezone_used: data.currentDate,
      message: isNightTime 
        ? "Night time (8 PM - 8 AM): Do not call" 
        : "Day time (8 AM - 8 PM): Safe to call"
    }
  });
}

return output;

